              CaptureMethod = None
              Currency = None
              Customer = None
              CustomerAccount = None
              Description = None
              ExcludedPaymentMethodTypes = None
              Expand = None
              Hooks = None
              Metadata = None
              PaymentDetails = None
              PaymentMethod = None
              PaymentMethodConfiguration = None
              PaymentMethodData = None
              PaymentMethodOptions = None
              PaymentMethodTypes = None
              ReceiptEmail = None
              SetupFutureUsage = None
              Shipping = None
              StatementDescriptor = None
              StatementDescriptorSuffix = None
              TransferData = None
              TransferGroup = None
            }

    ///<p>Returns a list of PaymentIntents.</p>
    let List settings (options: ListOptions) =
        let qs = [("created", options.Created |> box); ("customer", options.Customer |> box); ("customer_account", options.CustomerAccount |> box); ("ending_before", options.EndingBefore |> box); ("expand", options.Expand |> box); ("limit", options.Limit |> box); ("starting_after", options.StartingAfter |> box)] |> Map.ofList
        $"/v1/payment_intents"
        |> RestApi.getAsync<StripeList<PaymentIntent>> settings qs

    ///<p>Creates a PaymentIntent object.</p>
    ///<p>After the PaymentIntent is created, attach a payment method and <a href="/docs/api/payment_intents/confirm">confirm</a>
    ///to continue the payment. Learn more about <a href="/docs/payments/payment-intents">the available payment flows
    ///with the Payment Intents API</a>.</p>
    ///<p>When you use <code>confirm=true</code> during creation, it’s equivalent to creating
    ///and confirming the PaymentIntent in the same call. You can use any parameters
    ///available in the <a href="/docs/api/payment_intents/confirm">confirm API</a> when you supply
    ///<code>confirm=true</code>.</p>
    let Create settings (options: CreateOptions) =
        $"/v1/payment_intents"
        |> RestApi.postAsync<_, PaymentIntent> settings (Map.empty) options

    ///<p>Retrieves the details of a PaymentIntent that has previously been created. </p>
    ///<p>You can retrieve a PaymentIntent client-side using a publishable key when the <code>client_secret</code> is in the query string. </p>
    ///<p>If you retrieve a PaymentIntent with a publishable key, it only returns a subset of properties. Refer to the <a href="#payment_intent_object">payment intent</a> object reference for more details.</p>
    let Retrieve settings (options: RetrieveOptions) =
        let qs = [("client_secret", options.ClientSecret |> box); ("expand", options.Expand |> box)] |> Map.ofList
